@@ -0,0 +1,15 @@
+{
+  "name": "backspace_basic",
+  "description": "BS (0x08) moves cursor left one column; stops at column 0",
+  "initial_size": [80, 24],
+  "input_bytes_hex": "414243080844",
+  "comment": "A B C BS BS D → cursor was at col 3, BS to col 1, print D overwrites B",
+  "expected": {
+    "cursor": { "row": 0, "col": 2 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "A" },
+      { "row": 0, "col": 1, "char": "D" },
+      { "row": 0, "col": 2, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,15 @@
+{
+  "name": "cup_basic",
+  "description": "CUP (CSI row;col H) positions cursor using 1-indexed coordinates",
+  "initial_size": [80, 24],
+  "input_bytes_hex": "1b5b353b313048411b5b313b3148421b5b32343b383048431b5b313b314844",
+  "comment": "CUP(5,10)A CUP(1,1)B CUP(24,80)C CUP(1,1)D → B at (0,0) overwritten by D",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 0, "col": 0, "char": "D" },
+      { "row": 4, "col": 9, "char": "A" },
+      { "row": 23, "col": 79, "char": "C" }
+    ]
+  }
+}

@@ -0,0 +1,14 @@
+{
+  "name": "cup_bounds_clamp",
+  "description": "CUP with out-of-bounds coordinates is clamped to grid dimensions",
+  "initial_size": [80, 24],
+  "input_bytes_hex": "1b5b3939393b39393948411b5b303b304842",
+  "comment": "CUP(999,999)A → clamped to (23,79). CUP(0,0)B → treated as (1,1) → (0,0)",
+  "expected": {
+    "cursor": { "row": 0, "col": 1 },
+    "cells": [
+      { "row": 23, "col": 79, "char": "A" },
+      { "row": 0, "col": 0, "char": "B" }
+    ]
+  }
+}
